local R=loadstring(game:HttpGet('https://raw.githubusercontent.com/SiriusSoftwareLtd/Rayfield/main/source.lua'))() local W=R:CreateWindow({Name="N0XY MASTER ENGINE 💀 (v7)",LoadingTitle="N0XY CORE",LoadingSubtitle="by N0XY",ConfigurationSaving={Enabled=false}}) local P,LP,RS,L=game:GetService("Players"),game:GetService("Players").LocalPlayer,game:GetService("RunService"),game:GetService("Lighting") local fly,speed,noclip,anti,ws,jp,target,loopF,orbit,ka,jrk,mId=false,50,false,false,16,50,"",false,false,false,false,"" local ST={Space="rbxassetid://159454286",Fire="rbxassetid://1760874933",Night="rbxassetid://12128522303"} local function getT() for _,p in pairs(P:GetPlayers()) do if p.Name:lower():sub(1,#target)==target or p.DisplayName:lower():sub(1,#target)==target then return p end end end local function sAnim(id) pcall(function() for _,o in pairs(LP.Character.Animate:GetDescendants()) do if o:IsA("Animation") then o.AnimationId="rbxassetid://"..id end end end) end local T1,T2,T3,T4,T5,T6=W:CreateTab("PvP ⚔️"),W:CreateTab("Небо 🌌"),W:CreateTab("Тролл 😈"),W:CreateTab("Хаос 💥"),W:CreateTab("Аним 🎭"),W:CreateTab("Радио 🎵") T1:CreateToggle({Name="Fly",Callback=function(v) fly=v LP.Character.Humanoid.PlatformStand=v end}) T1:CreateSlider({Name="WalkSpeed",Range={16,250},CurrentValue=16,Callback=function(v) ws=v end}) T1:CreateToggle({Name="Noclip",Callback=function(v) noclip=v end}) T1:CreateToggle({Name="Anti-Fling",Callback=function(v) anti=v end}) T2:CreateDropdown({Name="Skybox",Options={"Space","Fire","Night"},Callback=function(o) local s=L:FindFirstChildOfClass("Sky") or Instance.new("Sky",L) s.SkyboxBk,s.SkyboxDn,s.SkyboxFt,s.SkyboxLf,s.SkyboxRt,s.SkyboxUp=ST[o],ST[o],ST[o],ST[o],ST[o],ST[o] end}) T3:CreateInput({Name="Ник",Callback=function(t) target=t:lower() end}) T3:CreateButton({Name="КЛЕТКА 🧱",Callback=function() local p=getT() if p and p.Character then local h=p.Character.HumanoidRootPart local m=Instance.new("Model",workspace) m.Name="RealCage_"..p.Name local pos={{-3.5,0,-3.5},{3.5,0,-3.5},{-3.5,0,3.5},{3.5,0,3.5}} for _,v in pairs(pos) do local b=Instance.new("Part",m) b.Size=Vector3.new(0.5,10,0.5) b.CFrame=h.CFrame*CFrame.new(v[1],v[2],v[3]) b.Anchored=true b.Material=Enum.Material.Iron end local t,b=Instance.new("Part",m),Instance.new("Part",m) t.Size=Vector3.new(8,0.5,8) t.CFrame=h.CFrame*CFrame.new(0,5,0) t.Anchored=true b.Size=Vector3.new(8,0.5,8) b.CFrame=h.CFrame*CFrame.new(0,-3.5,0) b.Anchored=true end end}) T3:CreateToggle({Name="Loop Fling",Callback=function(v) loopF = v while loopF and task.wait(0.01) do pcall(function() local p=getT() local m=LP.Character.HumanoidRootPart m.CFrame=p.Character.HumanoidRootPart.CFrame m.Velocity=Vector3.new(7000,7000,7000) end) end end}) T3:CreateToggle({Name="Orbit",Callback=function(v) orbit=v local a=0 while orbit and task.wait(0.01) do pcall(function() a=a+0.1 LP.Character.HumanoidRootPart.CFrame=CFrame.new(getT().Character.HumanoidRootPart.Position+Vector3.new(math.sin(a)*6,2,math.cos(a)*6),getT().Character.HumanoidRootPart.Position) end) end end}) T4:CreateToggle({Name="Ломаная Анимация",Callback=function(v) jrk=v while jrk and task.wait(0.01) do pcall(function() for _,j in pairs(LP.Character:GetDescendants()) do if j:IsA("Motor6D") then j.C0=j.C0*CFrame.Angles(math.rad(math.random(-10,10)),math.rad(math.random(-10,10)),math.rad(math.random(-10,10))) end end end) end end}) T4:CreateButton({Name="Стянуть блоки",Callback=function() for _,pt in pairs(workspace:GetDescendants()) do if pt:IsA("BasePart") and not pt.Anchored then pt.CFrame=LP.Character.HumanoidRootPart.CFrame end end end}) T5:CreateButton({Name="Маг",Callback=function() sAnim("707827244") end}) T5:CreateButton({Name="Ниндзя",Callback=function() sAnim("616111377") end}) T5:CreateButton({Name="Зомби",Callback=function() sAnim("616156730") end}) T5:CreateButton({Name="Оборотень",Callback=function() sAnim("1016149174") end}) T6:CreateInput({Name="ID Музыки",Callback=function(t) mId=t end}) T6:CreateButton({Name="Play 🔊",Callback=function() local s=workspace:FindFirstChild("N0XY_Radio") or Instance.new("Sound",workspace) s.Name="N0XY_Radio" s.SoundId="rbxassetid://"..mId s.Volume=2 s.Looped=true s:Play() end}) T6:CreateButton({Name="Stop 🔇",Callback=function() pcall(function() workspace.N0XY_Radio:Destroy() end) end}) RS.Stepped:Connect(function() if noclip and LP.Character then for _,pt in pairs(LP.Character:GetDescendants()) do if pt:IsA("BasePart") then pt.CanCollide=false end end end end) task.spawn(function() while task.wait(0.1) do pcall(function() LP.Character.Humanoid.WalkSpeed=ws LP.Character.Humanoid.JumpPower=jp end) end end)
